import boto3

def list_log_groups(prefix: str) -> list[str]:
    client = boto3.client('logs')
    log_group_names = []
    kwargs = {'logGroupNamePrefix': prefix, 'limit': 50}

    while True:
        response = client.describe_log_groups(**kwargs)
        for group in response.get('logGroups', []):
            log_group_names.append(group['logGroupName'])
        next_token = response.get('nextToken')
        if not next_token:
            break
        kwargs['nextToken'] = next_token

    return log_group_names

import boto3
import time

def wait_for_sqs_message(queue_url: str, body_contains: str, timeout: int = 30) -> str:
    client = boto3.client('sqs')
    deadline = time.time() + timeout

    while time.time() < deadline:
        remaining = deadline - time.time()
        wait_seconds = min(10, max(1, int(remaining)))
        response = client.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=wait_seconds
        )
        for message in response.get('Messages', []):
            if body_contains in message['Body']:
                client.delete_message(
                    QueueUrl=queue_url,
                    ReceiptHandle=message['ReceiptHandle']
                )
                return message['Body']

    raise TimeoutError(
        f"No message containing '{body_contains}' found in '{queue_url}' within {timeout}s"
    )

import boto3
from botocore.exceptions import ClientError

def get_parameter(name: str) -> str | None:
    client = boto3.client('ssm')
    try:
        response = client.get_parameter(
            Name=name,
            WithDecryption=True
        )
        return response['Parameter']['Value']
    except ClientError as e:
        if e.response['Error']['Code'] == 'ParameterNotFound':
            return None
        raise

import boto3
from botocore.exceptions import ClientError

def has_glacier_transition(bucket_name: str, max_days: int) -> bool:
    client = boto3.client('s3')
    try:
        response = client.get_bucket_lifecycle_configuration(Bucket=bucket_name)
    except ClientError as e:
        if e.response['Error']['Code'] == 'NoSuchLifecycleConfiguration':
            return False
        raise

    for rule in response.get('Rules', []):
        if rule.get('Status') != 'Enabled':
            continue
        for transition in rule.get('Transitions', []):
            if (
                transition.get('StorageClass') == 'GLACIER'
                and transition.get('Days', float('inf')) <= max_days
            ):
                return True
    return False

import boto3

def role_has_policy(role_name: str, policy_arn: str) -> bool:
    client = boto3.client('iam')
    kwargs = {'RoleName': role_name}

    while True:
        response = client.list_attached_role_policies(**kwargs)
        for policy in response.get('AttachedPolicies', []):
            if policy['PolicyArn'] == policy_arn:
                return True
        if response.get('IsTruncated'):
            kwargs['Marker'] = response['Marker']
        else:
            break

    return False
